// 处理最终结果
const data = $json;

// 调试信息
console.log('Process Result - 输入数据:', JSON.stringify(data, null, 2));

if (data.success && data.result) {
  const result = data.result;

  // 确保 data 是数组
  const queryData = (result.data && Array.isArray(result.data)) ? result.data : [];
  const rowCount = result.row_count || result.rowCount || queryData.length;
  const totalRows = result.total_rows || result.totalRows || rowCount;

  console.log('Process Result - 解析结果:', {
    rowCount,
    totalRows,
    dataLength: queryData.length,
    isArray: Array.isArray(queryData),
    resultKeys: Object.keys(result)
  });

  return {
    json: {
      success: true,
      queryId: data.queryId,
      status: data.status,
      rowCount: rowCount,
      totalRows: totalRows,
      executionTime: result.executionTime,
      data: queryData, // 确保这里是数组
      message: `查询成功！返回 ${rowCount} 条记录`,
      timestamp: new Date().toISOString()
    }
  };
} else {
  return {
    json: {
      success: false,
      queryId: data.queryId,
      status: data.status,
      error: data.error || '查询失败',
      message: data.message || '查询执行失败',
      timestamp: new Date().toISOString()
    }
  };
}

// Excel 导出功能
const data = $json;

console.log('Excel导出 - 输入数据检查:', {
  success: data.success,
  hasData: !!data.data,
  dataType: typeof data.data,
  isArray: Array.isArray(data.data),
  dataLength: data.data ? data.data.length : 0
});

// 检查数据是否有效
if (!data.success || !data.data || !Array.isArray(data.data) || data.data.length === 0) {
  return {
    json: {
      success: false,
      error: '数据格式错误，无法导出Excel',
      message: '查询数据为空或格式不正确',
      debug: {
        success: data.success,
        hasData: !!data.data,
        isArray: Array.isArray(data.data),
        dataLength: data.data ? data.data.length : 0
      }
    }
  };
}

// 准备Excel数据
const excelData = data.data.map((row, index) => {
  return {
    '序号': index + 1,
    '记录ID': row.id || '',
    '用户ID': row.uid || '',
    '商户ID': row.merchant_id || '',
    '游戏ID': row.game_id || '',
    '游戏代码': row.game_code || '',
    '游戏结果': row.result || '',
    '货币类型': row.currency || '',
    '投注金额': row.amount || '',
    '支付金额': row.pay_out || '',
    '倍数': row.multiplier || '',
    '余额': row.balance || '',
    '详细信息': row.detail || '',
    '创建时间': row.created_at || '',
    '更新时间': row.updated_at || '',
    '提供商': row.provider || '',
    '商户标识': row.merchant || ''
  };
});

// 生成文件名
const timestamp = new Date().toISOString().slice(0, 10);
const filename = `查询结果_${timestamp}_${Date.now()}`;

console.log(`Excel导出: 准备导出 ${excelData.length} 条记录到文件 ${filename}`);

return {
  json: {
    success: true,
    queryId: data.queryId,
    rowCount: data.rowCount,
    totalRows: data.totalRows,
    executionTime: data.executionTime,
    filename: filename,
    data: excelData, // 格式化后的数据
    message: `已准备好导出 ${data.rowCount} 条记录到Excel文件: ${filename}`,
    timestamp: new Date().toISOString()
  }
};

// 智能执行策略
const estimate = $json;
const originalSQL = $('AI Agent').item.json.output.generatedSQL;

if (!estimate.success) {
  return { json: { success: false, error: '预估失败', strategy: 'error' } };
}

const estimatedRows = estimate.estimatedRows;
const strategy = estimate.recommendedStrategy;

console.log(`查询预估: ${estimatedRows} 行, 策略: ${strategy}`);

// 根据预估结果选择执行策略
if (strategy === 'direct') {
  return {
    json: {
      strategy: 'direct',
      sql: originalSQL,
      estimatedRows: estimatedRows,
      message: `小数据量查询，直接执行 (${estimatedRows} 行)`
    }
  };
} else if (strategy === 'batch') {
  return {
    json: {
      strategy: 'batch',
      sql: originalSQL,
      batchSize: estimate.batchSize || 3000,
      estimatedBatches: estimate.estimatedBatches || Math.ceil(estimatedRows / 3000),
      estimatedRows: estimatedRows,
      message: `中等数据量查询，分批执行 (${estimatedRows} 行, ${estimate.estimatedBatches} 个批次)`
    }
  };
} else if (strategy === 'progressive') {
  return {
    json: {
      strategy: 'progressive',
      sql: originalSQL,
      estimatedRows: estimatedRows,
      message: `大数据量查询，渐进式执行 (${estimatedRows} 行)`
    }
  };
} else {
  return {
    json: {
      strategy: 'rejected',
      sql: originalSQL,
      estimatedRows: estimatedRows,
      message: `数据量过大 (${estimatedRows} 行)，请添加更具体的过滤条件`
    }
  };
}

// 记录查询ID到数据库或内存
const queryResponse = $json;

if (!queryResponse.success) {
  return {
    json: {
      success: false,
      error: '查询启动失败',
      message: queryResponse.error || '无法获取查询ID'
    }
  };
}

const queryId = queryResponse.queryId;
const originalMessage = $('Telegram Trigger').item.json.message.text;
const timestamp = new Date().toISOString();

console.log('记录查询ID:', {
  queryId: queryId,
  originalMessage: originalMessage,
  timestamp: timestamp
});

// 这里可以将查询ID记录到数据库
// 为了简化，我们先记录到内存中
const queryRecord = {
  queryId: queryId,
  originalMessage: originalMessage,
  status: 'pending',
  createdAt: timestamp,
  attempts: 0,
  lastChecked: timestamp
};

// 存储到全局变量（实际应用中应该存储到数据库）
if (!global.queryRecords) {
  global.queryRecords = new Map();
}
global.queryRecords.set(queryId, queryRecord);

return {
  json: {
    success: true,
    queryId: queryId,
    originalMessage: originalMessage,
    status: 'recorded',
    message: `查询ID ${queryId} 已记录，开始等待查询完成`,
    timestamp: timestamp
  }
};

// 定期检查查询状态
const recordData = $json;

if (!recordData.success) {
  return {
    json: {
      success: false,
      error: '查询记录失败',
      message: recordData.error || '无法记录查询ID'
    }
  };
}

const queryId = recordData.queryId;

// 从内存中获取查询记录
if (!global.queryRecords || !global.queryRecords.has(queryId)) {
  return {
    json: {
      success: false,
      error: '查询记录不存在',
      queryId: queryId
    }
  };
}

const queryRecord = global.queryRecords.get(queryId);
queryRecord.attempts += 1;
queryRecord.lastChecked = new Date().toISOString();

console.log(`检查查询状态: ${queryId}, 尝试次数: ${queryRecord.attempts}`);

// 如果尝试次数超过限制，标记为失败
if (queryRecord.attempts > 30) { // 30次 * 20秒 = 10分钟
  queryRecord.status = 'failed';
  global.queryRecords.set(queryId, queryRecord);

  return {
    json: {
      success: false,
      queryId: queryId,
      error: '查询超时',
      message: '查询超过10分钟仍未完成',
      attempts: queryRecord.attempts
    }
  };
}

// 返回查询ID供后续节点使用
return {
  json: {
    success: true,
    queryId: queryId,
    attempts: queryRecord.attempts,
    message: `第 ${queryRecord.attempts} 次检查查询状态`,
    status: 'checking'
  }
};

// 批量检查查询状态 - 增强版
const inputData = $json;

console.log('输入数据:', JSON.stringify(inputData, null, 2));

// 如果输入是数组，处理每个项目
if (Array.isArray(inputData)) {
  console.log(`批量处理 ${inputData.length} 个查询记录`);

  const results = [];

  for (let i = 0; i < inputData.length; i++) {
    const record = inputData[i];

    console.log(`检查记录 ${i}:`, {
      id: record.id,
      queryId: record.queryId,
      result: record.result,
      hasQueryId: !!record.queryId,
      queryIdType: typeof record.queryId,
      hasResult: !!record.result,
      resultIncludes: record.result ? record.result.includes('查询已启动') : false
    });

    // 严格检查：queryId 必须存在且不为null，result必须包含'查询已启动'
    if (record.queryId && 
        record.queryId !== null && 
        record.queryId !== 'null' && 
        typeof record.queryId === 'string' && 
        record.queryId.trim() !== '' &&
        record.result && 
        typeof record.result === 'string' && 
        record.result.includes('查询已启动')) {

      console.log(`✅ 处理查询ID: ${record.queryId}`);

      results.push({
        json: {
          id: record.id,
          queryId: record.queryId,
          originalResult: record.result,
          createdAt: record.createdAt,
          updatedAt: record.updatedAt,
          status: 'pending_check',
          message: `准备检查查询ID: ${record.queryId}`
        }
      });
    } else {
      console.log(`❌ 跳过记录 ID ${record.id}: queryId='${record.queryId}' (${typeof record.queryId}), result='${record.result}'`);
    }
  }

  console.log(`找到 ${results.length} 个需要检查的查询`);

  if (results.length === 0) {
    return {
      json: {
        status: 'no_valid_queries',
        message: '没有找到需要检查的有效查询',
        totalRecords: inputData.length
      }
    };
  }

  return results;
}

// 如果输入是单个对象
const record = inputData;

console.log('单个记录检查:', {
  id: record.id,
  queryId: record.queryId,
  result: record.result,
  hasQueryId: !!record.queryId,
  queryIdType: typeof record.queryId
});

if (record.queryId && 
    record.queryId !== null && 
    record.queryId !== 'null' && 
    typeof record.queryId === 'string' && 
    record.queryId.trim() !== '' &&
    record.result && 
    typeof record.result === 'string' && 
    record.result.includes('查询已启动')) {

  return {
    json: {
      id: record.id,
      queryId: record.queryId,
      originalResult: record.result,
      createdAt: record.createdAt,
      updatedAt: record.updatedAt,
      status: 'pending_check',
      message: `准备检查查询ID: ${record.queryId}`
    }
  };
} else {
  return {
    json: {
      id: record.id,
      queryId: record.queryId,
      status: 'skipped',
      message: `跳过检查: queryId='${record.queryId}' (${typeof record.queryId}), result='${record.result}'`,
      reason: 'queryId为空或result不包含查询已启动'
    }
  };
}

// 跳过无效查询
const data = $json;

console.log('跳过无效查询:', data);

return {
  json: {
    ...data,
    status: 'skipped',
    message: `跳过无效查询: ${data.message || '查询条件不满足'}`,
    timestamp: new Date().toISOString()
  }
};

// 处理查询状态检查结果
const statusData = $json;
const originalRecord = $('过滤待检查查询').item.json;

console.log('查询状态检查结果:', {
  queryId: originalRecord.queryId,
  status: statusData.status,
  success: statusData.success
});

if (!statusData.success) {
  return {
    json: {
      id: originalRecord.id,
      queryId: originalRecord.queryId,
      status: 'error',
      error: statusData.error || '状态检查失败',
      message: `查询 ${originalRecord.queryId} 状态检查失败`,
      originalResult: originalRecord.originalResult
    }
  };
}

const result = statusData.result;

// 检查查询是否完成
if (result && result.status === 'completed' && result.data) {
  // 查询已完成，准备导出Excel
  const queryData = Array.isArray(result.data) ? result.data : [result.data];
  const rowCount = result.row_count || result.rowCount || queryData.length;

  console.log(`查询完成: ${originalRecord.queryId}, 记录数: ${rowCount}`);

  return {
    json: {
      id: originalRecord.id,
      queryId: originalRecord.queryId,
      status: 'completed',
      rowCount: rowCount,
      totalRows: result.total_rows || result.totalRows || rowCount,
      executionTime: result.executionTime,
      data: queryData,
      message: `查询完成！返回 ${rowCount} 条记录`,
      originalResult: originalRecord.originalResult,
      readyForExport: true
    }
  };
} else if (result && result.status === 'running') {
  // 查询仍在运行
  return {
    json: {
      id: originalRecord.id,
      queryId: originalRecord.queryId,
      status: 'running',
      message: `查询仍在执行中: ${originalRecord.queryId}`,
      originalResult: originalRecord.originalResult,
      continueChecking: true
    }
  };
} else {
  // 其他状态
  return {
    json: {
      id: originalRecord.id,
      queryId: originalRecord.queryId,
      status: result?.status || 'unknown',
      message: `查询状态: ${result?.status || '未知'}`,
      originalResult: originalRecord.originalResult
    }
  };
}

// 处理SQL生成失败的情况
const originalMessage = $('Telegram Trigger').item.json.message;
const errorData = $json;

let errorMessage = `❌ *SQL生成失败*\n\n`;
errorMessage += `原始问题: ${originalMessage.text}\n\n`;
errorMessage += `错误信息: ${errorData.error || '无法将自然语言转换为SQL'}\n\n`;
errorMessage += `💡 *建议*:\n`;
errorMessage += `• 请使用更具体的查询条件\n`;
errorMessage += `• 例如: "查询用户ID为123的游戏记录"\n`;
errorMessage += `• 或者: "显示最近7天的交易数据"`;

return {
  json: {
    chatId: originalMessage.chat.id,
    messageId: originalMessage.message_id,
    replyText: errorMessage,
    success: false,
    error: errorData.error
  }
};

