// 知识库内容解析器 - 将AI Agent输出转换为知识库文档
const inputData = $json;

// 检查AI Agent的输出结构
let aiOutput;
if (inputData.output) {
  // 如果是结构化输出
  aiOutput = inputData.output;
} else if (inputData.text) {
  // 如果是文本输出，尝试解析JSON
  try {
    const jsonMatch = inputData.text.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      aiOutput = JSON.parse(jsonMatch[0]);
    } else {
      aiOutput = { error: '无法解析AI输出为JSON' };
    }
  } catch (error) {
    aiOutput = { error: 'JSON解析失败: ' + error.message };
  }
} else {
  aiOutput = { error: 'AI Agent输出不完整' };
}

// 提取关键信息
const queryType = aiOutput.queryType || '未知场景';
const confidence = aiOutput.confidence || 'Low';
const extractedInfo = aiOutput.extractedInfo || {};
const generatedSQL = aiOutput.generatedSQL || '';
const canExecute = aiOutput.canExecute || false;

// 如果查询可以执行，创建知识库文档
if (canExecute === true && generatedSQL) {
  // 创建知识库文档内容
  const knowledgeContent = `# ${queryType}场景案例

## 查询信息
- **场景类型**: ${queryType}
- **置信度**: ${confidence}
- **可执行**: 是

## 提取的信息
- **ID列表**: ${Array.isArray(extractedInfo.ids) ? extractedInfo.ids.join(', ') : (extractedInfo.ids || 'N/A')}
- **用户信息**: ${extractedInfo.userInfo || 'N/A'}
- **时间范围**: ${extractedInfo.timeRange || 'N/A'}
- **游戏信息**: ${extractedInfo.gameInfo || 'N/A'}
- **商户信息**: ${extractedInfo.merchantInfo || 'N/A'}

## 生成的SQL
\`\`\`sql
${generatedSQL}
\`\`\`

## 使用场景
当用户提供类似的查询请求时，可以使用此SQL模板进行查询。

## 注意事项
- 确保数据库连接正常
- 检查时间范围是否合理
- 验证ID格式是否正确
- 默认包含provider过滤条件：provider IN ('gp', 'popular')
- 限制结果数量使用LIMIT 100
`;

  // 创建知识库文档对象
  const knowledgeDocument = {
    content: knowledgeContent,
    metadata: {
      scenarioType: queryType,
      confidence: confidence,
      canExecute: 'Yes',
      extractedInfo: extractedInfo,
      generatedSQL: generatedSQL,
      timestamp: new Date().toISOString(),
      source: 'ai-agent-output',
      category: 'query-scenario',
      priority: confidence === 'High' ? 'high' : 'medium'
    }
  };

  return {
    json: {
      knowledgeDocument: knowledgeDocument,
      shouldAddToKnowledgeBase: true,
      scenarioType: queryType,
      confidence: confidence,
      extractedInfo: extractedInfo,
      generatedSQL: generatedSQL,
      canExecute: canExecute,
      // 为下一步准备的数据
      originalMessage: $('Telegram Trigger').item.json.message.text || 'Unknown message',
      chatId: $('Telegram Trigger').item.json.message.chat.id || '',
      messageId: $('Telegram Trigger').item.json.message.message_id || '',
      // 调试信息
      debug: {
        hasOutput: !!inputData.output,
        hasText: !!inputData.text,
        parsedOutput: aiOutput
      }
    }
  };
} else {
  // 如果查询不能执行，记录失败案例
  return {
    json: {
      shouldAddToKnowledgeBase: false,
      scenarioType: queryType,
      confidence: confidence,
      canExecute: canExecute,
      reason: 'Query cannot be executed',
      originalMessage: $('Telegram Trigger').item.json.message.text || 'Unknown message',
      chatId: $('Telegram Trigger').item.json.message.chat.id || '',
      messageId: $('Telegram Trigger').item.json.message.message_id || '',
      // 调试信息
      debug: {
        hasOutput: !!inputData.output,
        hasText: !!inputData.text,
        parsedOutput: aiOutput,
        error: aiOutput.error || 'Unknown error'
      }
    }
  };
}

// 知识库文档格式化器 - 将场景分析输出转换为Insert Documents需要的格式
const inputData = $json;

// 检查是否需要添加到知识库
if (!inputData.shouldAddToKnowledgeBase) {
  return {
    json: {
      skip: true,
      reason: "Query cannot be executed, skipping knowledge base update",
      debug: inputData.debug
    }
  };
}

// 提取关键信息
const scenarioType = inputData.scenarioType || '未知场景';
const confidence = inputData.confidence || 'Low';
const extractedInfo = inputData.extractedInfo || {};
const generatedSQL = inputData.generatedSQL || '';
const originalMessage = inputData.originalMessage || 'Unknown message';

// 创建知识库文档内容
const knowledgeContent = `# ${scenarioType}场景案例

## 查询信息
- **场景类型**: ${scenarioType}
- **置信度**: ${confidence}
- **可执行**: 是

## 原始查询消息
${originalMessage}

## 提取的信息
- **ID列表**: ${Array.isArray(extractedInfo.ids) ? extractedInfo.ids.join(', ') : (extractedInfo.ids || 'N/A')}
- **用户信息**: ${extractedInfo.userInfo || 'N/A'}
- **时间范围**: ${extractedInfo.timeRange || 'N/A'}
- **游戏信息**: ${extractedInfo.gameInfo || 'N/A'}
- **商户信息**: ${extractedInfo.merchantInfo || 'N/A'}

## 生成的SQL查询
\`\`\`sql
${generatedSQL}
\`\`\`

## 使用场景
当用户提供类似的查询请求时，可以使用此SQL模板进行查询。

## 注意事项
- 确保数据库连接正常
- 检查时间范围是否合理
- 验证ID格式是否正确
- 默认包含provider过滤条件：provider IN ('gp', 'popular')
- 限制结果数量使用LIMIT 100

## 相关场景
- ID查询场景
- 用户查询场景
- 商户查询场景
- 混合查询场景
`;

// 创建知识库文档对象（Insert Documents需要的格式）
const knowledgeDocument = {
  content: knowledgeContent,
  metadata: {
    scenarioType: scenarioType,
    confidence: confidence,
    canExecute: 'Yes',
    extractedInfo: extractedInfo,
    generatedSQL: generatedSQL,
    originalMessage: originalMessage,
    timestamp: new Date().toISOString(),
    source: 'ai-agent-output',
    category: 'query-scenario',
    priority: confidence === 'High' ? 'high' : 'medium',
    // 添加搜索关键词
    keywords: [
      scenarioType,
      Array.isArray(extractedInfo.ids) && extractedInfo.ids.length > 0 ? 'ID查询' : '',
      extractedInfo.userInfo ? '用户查询' : '',
      extractedInfo.merchantInfo ? '商户查询' : '',
      'SQL查询',
      '数据库查询'
    ].filter(k => k !== ''),
    // 添加场景标签
    tags: [
      'query-scenario',
      'sql-generation',
      'ai-learning',
      scenarioType.toLowerCase().replace(/\s+/g, '-')
    ]
  }
};

// 返回Insert Documents需要的格式
return {
  json: {
    documents: [knowledgeDocument],
    // 保留原始数据用于后续处理
    originalData: inputData,
    // 添加处理状态
    processed: true,
    knowledgeBaseUpdated: true,
    documentCount: 1,
    // 调试信息
    debug: {
      scenarioType: scenarioType,
      confidence: confidence,
      hasGeneratedSQL: !!generatedSQL,
      extractedInfoKeys: Object.keys(extractedInfo)
    }
  }
};
